 {"id":"asupersync-616","title":"Implement bulkhead combinator for resource isolation","description":"## Purpose
The bulkhead combinator isolates concurrent operations into partitions, preventing failures or resource exhaustion in one partition from affecting others. Named after ship compartments that contain flooding.

## Design Philosophy

### Key Features
1. **Isolation**: Failures contained to one partition
2. **Resource limits**: Bound concurrent operations per partition
3. **Fair scheduling**: FIFO queue ordering prevents starvation
4. **Cancel-aware**: Queue waiting respects cancellation
5. **Observable**: Metrics for monitoring utilization
6. **Composable**: Works with circuit breaker, rate limiter

### Permit Model
Bulkhead uses a permit system (similar to semaphore):
1. **Acquire permit** (may wait in queue)
2. **Execute operation** with permit held
3. **Release permit** on completion

## Implementation

### File: `src/combinator/bulkhead.rs`

```rust
use std::collections::HashMap;
use std::future::Future;
use std::pin::Pin;
use std::sync::atomic::{AtomicU32, AtomicU64, Ordering};
use std::sync::Arc;
use std::task::{Context, Poll, Waker};
use std::time::Duration;
use std::collections::VecDeque;
use parking_lot::Mutex;
use crate::cx::Cx;
use crate::types::Time;
use crate::error::Error;

// =========================================================================
// Policy Configuration
// =========================================================================

/// Bulkhead configuration
#[derive(Clone, Debug)]
pub struct BulkheadPolicy {
    /// Name for logging/metrics
    pub name: String,

    /// Maximum concurrent operations
    pub max_concurrent: u32,

    /// Maximum queue size (waiting operations)
    pub max_queue: u32,

    /// Maximum time to wait in queue
    pub queue_timeout: Duration,

    /// Enable weighted permits (operations can require multiple permits)
    pub weighted: bool,

    /// Callback when permits exhausted
    pub on_full: Option<FullCallback>,
}

pub type FullCallback = Arc<dyn Fn(&BulkheadMetrics) + Send + Sync>;

impl Default for BulkheadPolicy {
    fn default() -> Self {
        Self {
            name: "default".into(),
            max_concurrent: 10,
            max_queue: 100,
            queue_timeout: Duration::from_secs(5),
            weighted: false,
            on_full: None,
        }
    }
}

// =========================================================================
// Metrics & Observability
// =========================================================================

/// Metrics exposed by bulkhead
#[derive(Clone, Debug, Default)]
pub struct BulkheadMetrics {
    /// Currently active permits
    pub active_permits: u32,

    /// Current queue depth
    pub queue_depth: u32,

    /// Total operations executed
    pub total_executed: u64,

    /// Total operations queued
    pub total_queued: u64,

    /// Total operations rejected (queue full)
    pub total_rejected: u64,

    /// Total operations timed out in queue
    pub total_timeout: u64,

    /// Total operations cancelled while queued
    pub total_cancelled: u64,

    /// Average queue wait time (ms)
    pub avg_queue_wait_ms: f64,

    /// Max queue wait time (ms)
    pub max_queue_wait_ms: u64,

    /// Current utilization (active / max)
    pub utilization: f64,
}

// =========================================================================
// Queue Entry
// =========================================================================

struct QueueEntry {
    id: u64,
    waker: Option<Waker>,
    weight: u32,
    enqueued_at: Time,
    /// State of this entry: false = waiting, true = granted/cancelled
    completed: bool,
}

// =========================================================================
// Core Implementation
// =========================================================================

/// Thread-safe bulkhead
pub struct Bulkhead {
    policy: BulkheadPolicy,

    /// Available permits
    available_permits: AtomicU32,

    /// Queue of waiting operations
    queue: Mutex<VecDeque<QueueEntry>>,

    /// Next queue entry ID
    next_id: AtomicU64,

    /// Metrics
    metrics: parking_lot::RwLock<BulkheadMetrics>,

    /// Wait time accumulator for average calculation
    total_wait_time_ms: AtomicU64,
}

impl Bulkhead {
    pub fn new(policy: BulkheadPolicy) -> Self {
        let available = policy.max_concurrent;
        Self {
            policy,
            available_permits: AtomicU32::new(available),
            queue: Mutex::new(VecDeque::new()),
            next_id: AtomicU64::new(0),
            metrics: parking_lot::RwLock::new(BulkheadMetrics {
                utilization: 0.0,
                ..Default::default()
            }),
            total_wait_time_ms: AtomicU64::new(0),
        }
    }

    /// Get policy name
    pub fn name(&self) -> &str {
        &self.policy.name
    }

    /// Get current metrics
    pub fn metrics(&self) -> BulkheadMetrics {
        let mut m = self.metrics.read().clone();
        let queue = self.queue.lock();
        m.active_permits = self.policy.max_concurrent - self.available_permits.load(Ordering::SeqCst);
        m.queue_depth = queue.iter().filter(|e| !e.completed).count() as u32;
        m.utilization = m.active_permits as f64 / self.policy.max_concurrent as f64;
        m
    }

    /// Try to acquire permit without waiting
    fn try_acquire(&self, weight: u32) -> Option<BulkheadPermit> {
        loop {
            let available = self.available_permits.load(Ordering::SeqCst);
            if available >= weight {
                if self.available_permits.compare_exchange(
                    available,
                    available - weight,
                    Ordering::SeqCst,
                    Ordering::SeqCst,
                ).is_ok() {
                    return Some(BulkheadPermit { 
                        weight,
                        released: false,
                    });
                }
                // CAS failed, retry
            } else {
                return None;
            }
        }
    }

    /// Acquire permit, waiting in queue if necessary
    async fn acquire(&self, cx: &Cx<'_>, weight: u32) -> Result<BulkheadPermit, BulkheadError> {
        let now = cx.now();

        // Try immediate acquisition
        if let Some(permit) = self.try_acquire(weight) {
            tracing::trace!(
                bulkhead = %self.policy.name,
                weight = weight,
                "bulkhead: permit acquired immediately"
            );
            return Ok(permit);
        }

        // Check if queue is full
        {
            let queue = self.queue.lock();
            let active_count = queue.iter().filter(|e| !e.completed).count();
            if active_count >= self.policy.max_queue as usize {
                let mut metrics = self.metrics.write();
                metrics.total_rejected += 1;

                tracing::debug!(
                    bulkhead = %self.policy.name,
                    queue_depth = active_count,
                    "bulkhead: queue full, rejecting"
                );

                if let Some(ref callback) = self.policy.on_full {
                    callback(&*metrics);
                }

                return Err(BulkheadError::QueueFull);
            }
        }

        // Enqueue and wait
        let entry_id = self.next_id.fetch_add(1, Ordering::SeqCst);
        let deadline = now + self.policy.queue_timeout;

        tracing::trace!(
            bulkhead = %self.policy.name,
            entry_id = entry_id,
            weight = weight,
            "bulkhead: enqueueing"
        );

        {
            let mut metrics = self.metrics.write();
            metrics.total_queued += 1;
        }

        // Create future that waits for permit
        let permit = BulkheadWaitFuture {
            bulkhead: self,
            cx,
            entry_id,
            weight,
            enqueued_at: now,
            deadline,
            registered: false,
        }.await?;

        // Record wait time
        let wait_time = cx.now().duration_since(now);
        let wait_ms = wait_time.as_millis() as u64;
        self.total_wait_time_ms.fetch_add(wait_ms, Ordering::Relaxed);

        {
            let mut metrics = self.metrics.write();
            metrics.total_executed += 1;
            if wait_ms > metrics.max_queue_wait_ms {
                metrics.max_queue_wait_ms = wait_ms;
            }
            // Update running average
            let total = metrics.total_executed;
            if total > 0 {
                metrics.avg_queue_wait_ms = 
                    self.total_wait_time_ms.load(Ordering::Relaxed) as f64 / total as f64;
            }
        }

        Ok(permit)
    }

    /// Release permit (internal use - prefer RAII via permit drop)
    fn release_permit(&self, weight: u32) {
        self.available_permits.fetch_add(weight, Ordering::SeqCst);

        // Wake next waiter if any
        let mut queue = self.queue.lock();
        for entry in queue.iter_mut() {
            if !entry.completed {
                if let Some(ref waker) = entry.waker {
                    waker.wake_by_ref();
                }
                break;
            }
        }

        tracing::trace!(
            bulkhead = %self.policy.name,
            released_weight = weight,
            "bulkhead: permit released"
        );
    }

    /// Remove an entry from the queue (called on cancel/timeout)
    fn remove_entry(&self, entry_id: u64) {
        let mut queue = self.queue.lock();
        if let Some(entry) = queue.iter_mut().find(|e| e.id == entry_id) {
            entry.completed = true;
        }
        // Clean up old completed entries periodically
        while queue.front().map_or(false, |e| e.completed) {
            queue.pop_front();
        }
    }

    /// Record a cancellation
    fn record_cancellation(&self) {
        let mut metrics = self.metrics.write();
        metrics.total_cancelled += 1;
    }

    /// Record a timeout
    fn record_timeout(&self) {
        let mut metrics = self.metrics.write();
        metrics.total_timeout += 1;
    }
}

// =========================================================================
// Permit Guard (RAII)
// =========================================================================

/// RAII permit guard - automatically releases on drop
pub struct BulkheadPermit {
    weight: u32,
    released: bool,
}

impl BulkheadPermit {
    pub fn weight(&self) -> u32 {
        self.weight
    }

    /// Manually release the permit (to be called by the bulkhead holder)
    pub(crate) fn release_to(mut self, bulkhead: &Bulkhead) {
        if !self.released {
            bulkhead.release_permit(self.weight);
            self.released = true;
        }
    }
}

// Note: BulkheadPermit does not impl Drop because release needs a reference
// to the bulkhead. The combinator function handles release.

// =========================================================================
// Wait Future
// =========================================================================

struct BulkheadWaitFuture<'a, 'cx> {
    bulkhead: &'a Bulkhead,
    cx: &'a Cx<'cx>,
    entry_id: u64,
    weight: u32,
    enqueued_at: Time,
    deadline: Time,
    registered: bool,
}

impl<'a, 'cx> Future for BulkheadWaitFuture<'a, 'cx> {
    type Output = Result<BulkheadPermit, BulkheadError>;

    fn poll(mut self: Pin<&mut Self>, task_cx: &mut Context<'_>) -> Poll<Self::Output> {
        // Check cancellation via Cx
        if self.cx.is_cancelled() {
            self.bulkhead.remove_entry(self.entry_id);
            self.bulkhead.record_cancellation();
            return Poll::Ready(Err(BulkheadError::Cancelled));
        }

        // Check timeout using Cx for virtual time
        let now = self.cx.now();
        if now >= self.deadline {
            let waited = now.duration_since(self.enqueued_at);
            self.bulkhead.remove_entry(self.entry_id);
            self.bulkhead.record_timeout();

            tracing::debug!(
                bulkhead = %self.bulkhead.policy.name,
                entry_id = self.entry_id,
                waited_ms = waited.as_millis(),
                "bulkhead: queue timeout"
            );

            return Poll::Ready(Err(BulkheadError::QueueTimeout { waited }));
        }

        // Try to acquire
        if let Some(permit) = self.bulkhead.try_acquire(self.weight) {
            // Remove from queue
            self.bulkhead.remove_entry(self.entry_id);
            return Poll::Ready(Ok(permit));
        }

        // Register or update waker
        {
            let mut queue = self.bulkhead.queue.lock();
            if self.registered {
                // Update waker for existing entry
                if let Some(entry) = queue.iter_mut().find(|e| e.id == self.entry_id) {
                    entry.waker = Some(task_cx.waker().clone());
                }
            } else {
                // Register new entry
                queue.push_back(QueueEntry {
                    id: self.entry_id,
                    waker: Some(task_cx.waker().clone()),
                    weight: self.weight,
                    enqueued_at: self.enqueued_at,
                    completed: false,
                });
                self.registered = true;
            }
        }

        // Schedule wake at deadline for timeout check
        // This ensures we wake up even if no permits are released
        self.cx.schedule_wake_at(self.deadline, task_cx.waker().clone());

        Poll::Pending
    }
}

impl<'a, 'cx> Drop for BulkheadWaitFuture<'a, 'cx> {
    fn drop(&mut self) {
        // If dropped while still registered (cancelled), clean up
        if self.registered {
            self.bulkhead.remove_entry(self.entry_id);
        }
    }
}

// =========================================================================
// Error Types
// =========================================================================

/// Errors from bulkhead
#[derive(Debug, Clone)]
pub enum BulkheadError<E = Error> {
    /// Queue is full, cannot enqueue
    QueueFull,

    /// Timed out waiting in queue
    QueueTimeout { waited: Duration },

    /// Cancelled while waiting in queue
    Cancelled,

    /// Underlying operation error
    Inner(E),
}

impl<E: std::fmt::Display> std::fmt::Display for BulkheadError<E> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::QueueFull => write!(f, "bulkhead queue full"),
            Self::QueueTimeout { waited } => write!(f, "bulkhead queue timeout after {:?}", waited),
            Self::Cancelled => write!(f, "cancelled while waiting for bulkhead"),
            Self::Inner(e) => write!(f, "{}", e),
        }
    }
}

impl<E: std::fmt::Debug + std::fmt::Display> std::error::Error for BulkheadError<E> {}

// =========================================================================
// Combinator Function
// =========================================================================

/// Execute operation with bulkhead protection
pub async fn with_bulkhead<T, E>(
    cx: &mut Cx<'_>,
    bulkhead: &Bulkhead,
    op: impl Future<Output = Result<T, E>>,
) -> Result<T, BulkheadError<E>>
where
    E: Into<Error>,
{
    with_bulkhead_weighted(cx, bulkhead, 1, op).await
}

/// Execute operation with weighted bulkhead protection
pub async fn with_bulkhead_weighted<T, E>(
    cx: &mut Cx<'_>,
    bulkhead: &Bulkhead,
    weight: u32,
    op: impl Future<Output = Result<T, E>>,
) -> Result<T, BulkheadError<E>>
where
    E: Into<Error>,
{
    // Acquire permit (may wait)
    let permit = bulkhead.acquire(cx, weight).await?;

    tracing::trace!(
        bulkhead = %bulkhead.policy.name,
        weight = weight,
        "bulkhead: executing operation"
    );

    // Execute operation (cancel-aware via select with cx.cancelled())
    let result = cx.with_cancel_guard(op).await;

    // Always release permit, even on cancel/panic
    permit.release_to(bulkhead);

    match result {
        Ok(Ok(v)) => Ok(v),
        Ok(Err(e)) => Err(BulkheadError::Inner(e.into())),
        Err(_cancelled) => Err(BulkheadError::Cancelled),
    }
}

// =========================================================================
// Registry for Named Bulkheads
// =========================================================================

/// Registry for managing multiple named bulkheads
pub struct BulkheadRegistry {
    bulkheads: parking_lot::RwLock<HashMap<String, Arc<Bulkhead>>>,
    default_policy: BulkheadPolicy,
}

impl BulkheadRegistry {
    pub fn new(default_policy: BulkheadPolicy) -> Self {
        Self {
            bulkheads: parking_lot::RwLock::new(HashMap::new()),
            default_policy,
        }
    }

    /// Get or create a named bulkhead
    pub fn get_or_create(&self, name: &str) -> Arc<Bulkhead> {
        // Fast path: read lock
        {
            let bulkheads = self.bulkheads.read();
            if let Some(b) = bulkheads.get(name) {
                return b.clone();
            }
        }

        // Slow path: write lock
        let mut bulkheads = self.bulkheads.write();
        bulkheads.entry(name.to_string())
            .or_insert_with(|| {
                Arc::new(Bulkhead::new(BulkheadPolicy {
                    name: name.to_string(),
                    ..self.default_policy.clone()
                }))
            })
            .clone()
    }

    /// Get or create with custom policy
    pub fn get_or_create_with(&self, name: &str, policy: BulkheadPolicy) -> Arc<Bulkhead> {
        let mut bulkheads = self.bulkheads.write();
        bulkheads.entry(name.to_string())
            .or_insert_with(|| Arc::new(Bulkhead::new(policy)))
            .clone()
    }

    /// Get metrics for all bulkheads
    pub fn all_metrics(&self) -> HashMap<String, BulkheadMetrics> {
        let bulkheads = self.bulkheads.read();
        bulkheads.iter()
            .map(|(name, b)| (name.clone(), b.metrics()))
            .collect()
    }

    /// Remove a named bulkhead
    pub fn remove(&self, name: &str) -> Option<Arc<Bulkhead>> {
        let mut bulkheads = self.bulkheads.write();
        bulkheads.remove(name)
    }
}
