//! E2E tests for bulkhead combinator.

use asupersync::combinator::bulkhead::*;
use asupersync::lab::{LabRuntime, LabConfig};
use parking_lot::Mutex;
use std::sync::Arc;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::time::Duration;

/// Test: Bulkhead limits concurrent operations to max_concurrent
/// Expected: Peak concurrency never exceeds configured limit
#[test]
fn e2e_bulkhead_limits_concurrency() {
    println!("[TEST] e2e_bulkhead_limits_concurrency");
    println!("  Config: max_concurrent=3, max_queue=100, 10 operations");

    let mut rt = LabRuntime::new();

    let max_concurrent = Arc::new(AtomicUsize::new(0));
    let peak_concurrent = Arc::new(AtomicUsize::new(0));

    let bulkhead = Arc::new(Bulkhead::new(BulkheadPolicy {
        name: "test".into(),
        max_concurrent: 3,
        max_queue: 100,
        queue_timeout: Duration::from_secs(10),
        ..Default::default()
    }));

    rt.block_on(async {
        let cx = rt.root_cx();

        cx.region(|sub| async move {
            let mut handles = vec![];

            // Launch 10 concurrent operations
            for i in 0..10 {
                let bh = bulkhead.clone();
                let mc = max_concurrent.clone();
                let pc = peak_concurrent.clone();

                handles.push(sub.spawn(async move |cx| {
                    println!("    [op {}] attempting to acquire permit", i);

                    with_bulkhead(&cx, &bh, async {
                        // Track concurrent count
                        let current = mc.fetch_add(1, Ordering::SeqCst) + 1;
                        println!("    [op {}] acquired permit, concurrent={}", i, current);

                        // Update peak
                        pc.fetch_max(current, Ordering::SeqCst);

                        // Simulate work
                        cx.sleep(Duration::from_millis(100)).await;

                        let after = mc.fetch_sub(1, Ordering::SeqCst) - 1;
                        println!("    [op {}] releasing permit, concurrent={}", i, after);
                        Ok::<_, String>(())
                    }).await
                }));
            }

            for h in handles {
                h.await.unwrap();
            }
        }).await;
    });

    let peak = peak_concurrent.load(Ordering::SeqCst);
    println!("  Result: peak_concurrent={}", peak);

    // Peak should never exceed max_concurrent
    assert!(
        peak <= 3,
        "Peak concurrent {} exceeded limit 3",
        peak
    );

    println!("  PASSED\n");
}

