        max_queue: 2,
        queue_timeout: Duration::from_secs(60),
        ..Default::default()
    }));

    rt.block_on(async {
        let cx = rt.root_cx();

        cx.region(|sub| async move {
            let mut handles = vec![];

            // Launch 10 operations with capacity for 3 (1 active + 2 queued)
            for i in 0..10 {
                let bh = bulkhead.clone();
                let rc = rejected_count.clone();
                let qc = queued_count.clone();

                handles.push(sub.spawn(async move |cx| {
                    println!("    [op {}] attempting to acquire", i);

                    let result: Result<(), BulkheadError<String>> = 
                        with_bulkhead(&cx, &bh, async {
                            qc.fetch_add(1, Ordering::SeqCst);
                            cx.sleep(Duration::from_secs(10)).await;
                            Ok(())
                        }).await;

                    match &result {
                        Err(BulkheadError::QueueFull) => {
                            println!("    [op {}] rejected - queue full", i);
                            rc.fetch_add(1, Ordering::SeqCst);
                        }
                        Ok(_) => println!("    [op {}] completed", i),
                        Err(e) => println!("    [op {}] error: {}", i, e),
                    }
                }));
            }

            // Let some tasks fail immediately
            cx.sleep(Duration::from_millis(10)).await;

            // Cancel remaining
            for h in handles {
                h.cancel();
            }
        }).await;
    });

    let rejected = rejected_count.load(Ordering::SeqCst);
    println!("  Result: rejected={}", rejected);

    // 7 should be rejected (10 - 1 active - 2 queued)
    assert_eq!(rejected, 7, "Expected 7 rejections, got {}", rejected);

    println!("  PASSED\n");
}

/// Test: Queue timeout triggers QueueTimeout error
/// Expected: Operations waiting beyond timeout are rejected with QueueTimeout
#[test]
fn e2e_bulkhead_queue_timeout() {
    println!("[TEST] e2e_bulkhead_queue_timeout");
    println!("  Config: max_concurrent=1, queue_timeout=100ms");

    let mut rt = LabRuntime::new();

    let timeout_count = Arc::new(AtomicUsize::new(0));

    let bulkhead = Arc::new(Bulkhead::new(BulkheadPolicy {
        name: "test".into(),
        max_concurrent: 1,
        max_queue: 10,
        queue_timeout: Duration::from_millis(100),
        ..Default::default()
    }));

    rt.block_on(async {
        let cx = rt.root_cx();

        cx.region(|sub| async move {
            // First operation holds permit for long time
            let bh = bulkhead.clone();
            let blocker = sub.spawn(async move |cx| {
                println!("    [blocker] acquiring permit");
                with_bulkhead(&cx, &bh, async {
                    println!("    [blocker] holding permit for 10s");
                    cx.sleep(Duration::from_secs(10)).await;
                    Ok::<_, String>(())
                }).await
            });

            // Wait for blocker to acquire
            cx.sleep(Duration::from_millis(10)).await;

            // Second operation should timeout
            let tc = timeout_count.clone();
            let bh = bulkhead.clone();
            let waiter = sub.spawn(async move |cx| {
                println!("    [waiter] attempting to acquire");
                let result: Result<(), BulkheadError<String>> = 
                    with_bulkhead(&cx, &bh, async {
                        Ok(())
                    }).await;

                match &result {
                    Err(BulkheadError::QueueTimeout { waited }) => {
                        println!("    [waiter] timed out after {:?}", waited);
                        tc.fetch_add(1, Ordering::SeqCst);
                    }
                    Ok(_) => println!("    [waiter] unexpectedly succeeded"),
                    Err(e) => println!("    [waiter] other error: {}", e),
                }
            });

            // Wait for timeout
            cx.sleep(Duration::from_millis(200)).await;

            println!("    [cleanup] cancelling blocker");
            blocker.cancel();
        }).await;
    });

    let timeouts = timeout_count.load(Ordering::SeqCst);
    println!("  Result: timeout_count={}", timeouts);

    assert_eq!(timeouts, 1, "Expected 1 timeout, got {}", timeouts);

    println!("  PASSED\n");
}

/// Test: FIFO ordering for queued operations
/// Expected: Operations complete in the order they were queued
#[test]
fn e2e_bulkhead_fifo_ordering() {
    println!("[TEST] e2e_bulkhead_fifo_ordering");
    println!("  Config: max_concurrent=1, 5 queued operations");

    let mut rt = LabRuntime::new();

    let order = Arc::new(Mutex::new(Vec::new()));

    let bulkhead = Arc::new(Bulkhead::new(BulkheadPolicy {
        name: "test".into(),
        max_concurrent: 1,
        max_queue: 10,
        queue_timeout: Duration::from_secs(10),
        ..Default::default()
    }));

    rt.block_on(async {
        let cx = rt.root_cx();

        // Hold permit briefly
        let bh = bulkhead.clone();
        let holder = cx.spawn(async move |cx| {
            println!("    [holder] acquiring initial permit");
            with_bulkhead(&cx, &bh, async {
                println!("    [holder] holding for 50ms");
                cx.sleep(Duration::from_millis(50)).await;
                Ok::<_, String>(())
            }).await
        });

        // Wait for holder to acquire
        cx.sleep(Duration::from_millis(10)).await;

        // Queue operations in order
        let mut handles = vec![];
        for i in 0..5 {
            let bh = bulkhead.clone();
            let ord = order.clone();

            // Stagger spawns to ensure ordering
            cx.sleep(Duration::from_millis(1)).await;
            println!("    [op {}] spawning", i);

            handles.push(cx.spawn(async move |cx| {
                with_bulkhead(&cx, &bh, async {
                    println!("    [op {}] executing", i);
                    ord.lock().push(i);
                    Ok::<_, String>(())
                }).await
            }));
        }

        // Wait for all to complete
        holder.await.unwrap();
        for (i, h) in handles.into_iter().enumerate() {
            println!("    [op {}] awaiting completion", i);
            h.await.unwrap();
        }
    });

    let final_order = order.lock().clone();
    println!("  Result: execution_order={:?}", final_order);

    assert_eq!(
        final_order, vec![0, 1, 2, 3, 4], 
        "Operations should complete in FIFO order"
    );

    println!("  PASSED\n");
}

/// Test: Cancellation while queued triggers Cancelled error
/// Expected: Cancelled operations in queue receive Cancelled error
#[test]
fn e2e_bulkhead_cancellation_while_queued() {
    println!("[TEST] e2e_bulkhead_cancellation_while_queued");

    let mut rt = LabRuntime::new();

    let cancelled = Arc::new(AtomicUsize::new(0));

    let bulkhead = Arc::new(Bulkhead::new(BulkheadPolicy {
        name: "test".into(),
        max_concurrent: 1,
        max_queue: 10,
        queue_timeout: Duration::from_secs(60),
        ..Default::default()
    }));

    rt.block_on(async {
        let cx = rt.root_cx();

        cx.region(|sub| async move {
            // Blocker
            let bh = bulkhead.clone();
            let blocker = sub.spawn(async move |cx| {
                println!("    [blocker] acquiring permit");
                with_bulkhead(&cx, &bh, async {
                    println!("    [blocker] holding for 60s");
                    cx.sleep(Duration::from_secs(60)).await;
                    Ok::<_, String>(())
                }).await
            });

            cx.sleep(Duration::from_millis(10)).await;

            // Queued waiter
            let bh = bulkhead.clone();
            let canc = cancelled.clone();
            let waiter = sub.spawn(async move |cx| {
                println!("    [waiter] attempting to acquire (will be queued)");
                let result: Result<(), BulkheadError<String>> = 
                    with_bulkhead(&cx, &bh, async {
                        Ok(())
                    }).await;

                match &result {
