/// Expected: Same seed produces identical execution order
#[test]
fn e2e_bulkhead_deterministic() {
    println!("[TEST] e2e_bulkhead_deterministic");

    fn run_scenario(seed: u64) -> Vec<u64> {
        println!("    [seed={}] running scenario", seed);

        let config = LabConfig {
            entropy_seed: seed,
            ..Default::default()
        };

        let mut rt = LabRuntime::with_config(config);
        let results = Arc::new(Mutex::new(Vec::new()));

        let bulkhead = Arc::new(Bulkhead::new(BulkheadPolicy {
            name: "test".into(),
            max_concurrent: 2,
            max_queue: 10,
            queue_timeout: Duration::from_secs(1),
            ..Default::default()
        }));

        rt.block_on(async {
            let cx = rt.root_cx();

            cx.region(|sub| async move {
                let mut handles = vec![];

                for i in 0..10u64 {
                    let bh = bulkhead.clone();
                    let res = results.clone();

                    handles.push(sub.spawn(async move |cx| {
                        let r = with_bulkhead(&cx, &bh, async {
                            cx.sleep(Duration::from_millis(10)).await;
                            Ok::<_, String>(i)
                        }).await;

