    println!("  Config: max_concurrent=10, operations with weight 5");

    let mut rt = LabRuntime::new();

    let peak_weight = Arc::new(AtomicUsize::new(0));
    let current_weight = Arc::new(AtomicUsize::new(0));

    let bulkhead = Arc::new(Bulkhead::new(BulkheadPolicy {
        name: "weighted-test".into(),
        max_concurrent: 10,
        max_queue: 10,
