        ..Default::default()
    }));

    rt.block_on(async {
        let cx = rt.root_cx();

        cx.region(|sub| async move {
            let mut handles = vec![];

            // Launch 5 operations each requiring 5 permits
            for i in 0..5 {
                let bh = bulkhead.clone();
                let cw = current_weight.clone();
                let pw = peak_weight.clone();

                handles.push(sub.spawn(async move |cx| {
                    println!("    [op {}] attempting to acquire (weight=5)", i);

                    with_bulkhead_weighted(&cx, &bh, 5, async {
