pub struct VirtualClient {
    lab: Arc<LabRuntime>,
}

impl VirtualClient {
    /// Send GET request.
    pub async fn get(&self, url: &str) -> Outcome<Response, ClientError> {
        self.request(Method::GET, url, None).await
    }

    /// Send POST request with body.
    pub async fn post(&self, url: &str, body: impl Into<Body>) -> Outcome<Response, ClientError>;

    /// Build custom request.
    pub fn request_builder(&self) -> RequestBuilder;
}
