### 3. Virtual Time for Timeout Testing
```rust
#[test]
fn test_request_timeout() {
    let lab = LabRuntime::new();

    lab.block_on(async {
        let cx = lab.cx_with_budget(Budget::deadline_ns(1_000_000_000)); // 1 second

        // Handler that sleeps "forever"
        let server = VirtualServer::bind(&lab, "localhost:8080")
            .route("/slow", |cx| async {
                cx.sleep(Duration::from_secs(3600)).await; // Virtual sleep
                Outcome::Ok(Response::ok())
            });

        // Advance virtual time by 1 second
        lab.advance_time(Duration::from_secs(1));

        // Request should have timed out
        let result = lab.client().get("http://localhost:8080/slow").await;
        assert!(matches!(result, Outcome::Cancelled(_)));
    });
}
```

### 4. Deterministic Request Scheduling
```rust
#[test]
fn test_request_interleaving() {
    // Fixed seed for reproducibility
    let lab = LabRuntime::with_seed(0xDEADBEEF);

    let request_order = Arc::new(Mutex::new(Vec::new()));
    let order_clone = request_order.clone();

    lab.block_on(async {
        let server = VirtualServer::bind(&lab, "localhost:8080")
            .route("/record/:id", move |cx, params| {
                let id = params.get("id").unwrap().clone();
                let order = order_clone.clone();
                async move {
                    order.lock().unwrap().push(id);
                    Outcome::Ok(Response::ok())
                }
            });

        // Fire 3 concurrent requests
        let (a, b, c) = join3(
            lab.client().get("http://localhost:8080/record/A"),
            lab.client().get("http://localhost:8080/record/B"),
            lab.client().get("http://localhost:8080/record/C"),
        ).await;

        // With seed 0xDEADBEEF, order is always: B, C, A (for example)
        // Different seed -> different order, but deterministic
        let order = request_order.lock().unwrap();
        assert_eq!(order.as_slice(), &["B", "C", "A"]);
    });
}
```

